class Solution {
public:
    vector<int> maxDepthAfterSplit(string seq) {
        vector<int> answer(seq.size());
        int depth = 0;
        for (int i = 0; i < seq.size(); ++i) {
            if (seq[i] == '(') {
                depth++;
                answer[i] = 0;
            } else {
                depth--;
                answer[i] = 1;
            }
        }
        return answer;
    }
};
